  unsigned int src_idx = 0;
  unsigned int dest_idx = 0;
  if ((((&dest[dest_idx]) == 0) || ((&src[src_idx]) == 0)) || (dest_size == 0))
  {
    return;
  }
  while ((src[src_idx] != 0) && (dest_size > 1))
  {
    dest[dest_idx] = src[src_idx];
    src_idx += 1;
    dest_idx += 1;
    dest_size -= 1;
