static void mi_outs(const char *s, char **out, char *end)
{
  unsigned int s_idx = 0;
  if ((&s[s_idx]) == 0)
  {
    return;
  }
  char *p = *out;
  unsigned int p_idx = 0;
  while ((s[s_idx] != 0) && ((&p[p_idx]) < end))
  {
    p[p_idx] = s[s_idx];
    s_idx += 1;
    p_idx += 1;
  }

  *out = &p[p_idx];
}

