pub fn mi_prim_read(fd: std::os::fd::RawFd, buf: *mut u8, bufsize: usize) -> isize {
    unsafe {
        let result: isize;

        #[cfg(target_os = "linux")]
        #[cfg(target_arch = "x86_64")]
        {
            const SYS_READ: i64 = 0;
            let syscall_num = SYS_READ;
            core::arch::asm!(
                "syscall",
                in("rax") syscall_num,
                in("rdi") fd,
                in("rsi") buf,
                in("rdx") bufsize,
                out("rcx") _, // clobbered by syscall
                out("r11") _, // clobbered by syscall
                lateout("rax") result,
                options(nostack)
            );
        }

        #[cfg(target_os = "linux")]
        #[cfg(target_arch = "x86")]
        {
            const SYS_READ: i32 = 3;
            let syscall_num = SYS_READ;
            core::arch::asm!(
                "int 0x80",
                in("eax") syscall_num,
                in("ebx") fd as i32,
                in("ecx") buf,
                in("edx") bufsize as u32,
                lateout("eax") result,
                options(nostack)
            );
        }

        #[cfg(not(any(
            all(target_os = "linux", target_arch = "x86_64"),
            all(target_os = "linux", target_arch = "x86")
        )))]
        {
            // Use libc's read function as fallback
            result = libc::read(fd as i32, buf as *mut _, bufsize as _) as isize;
        }

        result
    }
}

