  }
  else
    if (mi_option_is_enabled(mi_option_purge_decommits) && (!_mi_preloading()))
  {
    bool needs_recommit = 1;
    mi_os_decommit_ex(p, size, &needs_recommit, stat_size);
    return needs_recommit;
