inline static void qround(uint32_t x[16], size_t a, size_t b, size_t c, size_t d)
{
  x[a] += x[b];
  x[d] = mi_rotl32(x[d] ^ x[a], 16);
  x[c] += x[d];
  x[b] = mi_rotl32(x[b] ^ x[c], 12);
  x[a] += x[b];
  x[d] = mi_rotl32(x[d] ^ x[a], 8);
  x[c] += x[d];
  x[b] = mi_rotl32(x[b] ^ x[c], 7);
}

