static void chacha_block(mi_random_ctx_t *ctx)
{
  uint32_t x[16];
  for (size_t i = 0; i < 16; i += 1)
  {
    x[i] = ctx->input[i];
  }

  for (size_t i = 0; i < 20; i += 2)
  {
    qround(x, 0, 4, 8, 12);
    qround(x, 1, 5, 9, 13);
    qround(x, 2, 6, 10, 14);
    qround(x, 3, 7, 11, 15);
    qround(x, 0, 5, 10, 15);
    qround(x, 1, 6, 11, 12);
    qround(x, 2, 7, 8, 13);
    qround(x, 3, 4, 9, 14);
  }

  for (size_t i = 0; i < 16; i += 1)
  {
    ctx->output[i] = x[i] + ctx->input[i];
  }

  ctx->output_available = 16;
  ctx->input[12] += 1;
  if (ctx->input[12] == 0)
  {
    ctx->input[13] += 1;
    if (ctx->input[13] == 0)
    {
      ctx->input[14] += 1;
    }
  }
}

