            } else {
                // page was the last in the queue
                from_queue.last = prev_page;
            }

            from_queue.count = from_queue.count.wrapping_sub(1);
        }

        // Add page to 'to' queue at the end
        if !to.is_null() {
            let to_queue = &mut *to;
            (*page).prev = to_queue.last;
