pub fn mi_debug_show_bfield(field: mi_bfield_t, buf: &mut [u8], k: &[usize]) -> usize {
    let mut k_idx = 0;
    let mut bit_set_count = 0;

    for bit in 0..(1 << (3 + 3)) {
        let is_set = ((1 as mi_bfield_t) << bit) & field != 0;

        if is_set {
            bit_set_count += 1;
        }

        if k_idx < k.len() && k[k_idx] < buf.len() {
            buf[k[k_idx]] = if is_set { b'x' } else { b'.' };
        }

        k_idx += 1;
    }

    bit_set_count
}

