bool _mi_meta_is_meta_page(void *p)
{
  mi_meta_page_t *mpage0 = atomic_load_explicit(&mi_meta_pages, memory_order_acquire);
  mi_meta_page_t *mpage = mpage0;
  unsigned int mpage_idx = 0;
  while ((&mpage[mpage_idx]) != 0)
