static bool mi_bchunk_bsr(mi_bchunk_t *chunk, size_t *pidx)
{
  for (size_t i = (1 << (6 + 3)) / (1 << (3 + 3)); i > 0;)
  {
    i -= 1;
    mi_bfield_t b = atomic_load_explicit(&chunk->bfields[i], memory_order_relaxed);
    size_t idx;
    if (mi_bsr(b, &idx))
    {
      *pidx = (i * (1 << (3 + 3))) + idx;
      return 1;
    }
  }

  return 0;
}

