{
  for (mi_chunkbin_t ibin = MI_CBIN_SMALL; ibin < MI_CBIN_NONE; ibin = mi_chunkbin_inc(ibin))
  {
    if (mi_bchunk_is_xsetN(1, &chunkmap_bins[ibin], chunk_idx, 1))
