    } else {
        None
    };

    // Reallocate using C function
    let new_ptr = mi_rezalloc(current_ptr, newsize);

    match new_ptr {
        Some(ptr) if !ptr.is_null() => {
            // Convert raw pointer back to Vec<u8>
            unsafe {
                hbuf.buf = Some(Vec::from_raw_parts(
                    ptr as *mut u8,
                    hbuf.size,
                    newsize
                ));
            }
            hbuf.size = newsize;
            true
        }
        _ => false,
    }
}

