char *mi_stats_get_json(size_t output_size, char *output_buf)
{
  mi_stats_merge();
  mi_heap_buf_t hbuf = {0, 0, 0, 1};
  if ((output_size > 0) && (output_buf != 0))
  {
    _mi_memzero(output_buf, output_size);
